SELECT patients.name, devices.device_name, devices.model
FROM patients
JOIN devices ON patients.patient_id = devices.patient_id;

SELECT AVG(total_minutes_asleep) AS average_duration_of_slumber
FROM sleep_data
WHERE patient_id = (SELECT patient_id FROM patients WHERE name = 'John Doe');

SELECT patient_id, goal_value
FROM sleep_goals
WHERE goal_type = 'duration' AND goal_value >= 7;

SELECT patient_id
FROM sleep_quality_scores
WHERE score > 80;

SELECT patient_id, stage_type, MAX(stage_duration) AS longest_duration
FROM patient_sleep_stage
GROUP BY patient_id, stage_type;

SELECT patients.patient_id, patients.name
FROM patients
WHERE patients.patient_id NOT IN (
    SELECT patient_id
    FROM sleep_goals
);
